//! Sovereign, local, embedding-based tool-relevance scoring — a targeted
//! addition alongside the lexical scorer (`score_indexed_tool`), not a
//! replacement. Reuses fat-station's existing `/hidden-embed` (one text,
//! forward-pass + mean-pool) and `/hidden-embed-batch` (many texts, one
//! weight-dequant pass for the whole batch) endpoints — no new fat-station
//! capability was needed for this.
//!
//! Cost shape: the steady-state per-turn cost is one `/hidden-embed` call on
//! the query only (a handful of tokens) — noise next to the decode loop's
//! own per-token cost for the eventual answer. The one-time cost (embedding
//! every catalog tool description) happens once ever per unique
//! `(name, description)` pair, persisted to disk by `tool_embed_cache` and
//! reused across every future session.

use anyhow::{anyhow, Result};
use std::time::Duration;

use super::agent_tools::{AgentIndexedTool, AgentToolIndex};
use super::tool_embed_cache::{content_key, ToolEmbedCache};

fn fat_station_base() -> String {
    format!("http://127.0.0.1:{}", super::fat_station_port())
}

fn tokens_to_body(tokens: &[u32]) -> Vec<u8> {
    let mut out = Vec::with_capacity(tokens.len() * 4);
    for t in tokens {
        out.extend_from_slice(&t.to_le_bytes());
    }
    out
}

fn body_to_f32(body: &[u8]) -> Vec<f32> {
    body.chunks_exact(4)
        .map(|c| f32::from_le_bytes([c[0], c[1], c[2], c[3]]))
        .collect()
}

async fn tokenize_via_mesh(client: &reqwest::Client, base: &str, text: &str) -> Result<Vec<u32>> {
    let resp = client
        .post(format!("{}/tokenize", base))
        .json(&serde_json::json!({ "text": text }))
        .send()
        .await
        .map_err(|e| anyhow!("/tokenize request failed: {}", e))?;
    if !resp.status().is_success() {
        let status = resp.status();
        let body = resp.text().await.unwrap_or_default();
        return Err(anyhow!("/tokenize returned {}: {}", status, body));
    }
    let json: serde_json::Value = resp.json().await?;
    let tokens = json
        .get("tokens")
        .and_then(|v| v.as_array())
        .ok_or_else(|| anyhow!("/tokenize response missing 'tokens' array"))?
        .iter()
        .filter_map(|v| v.as_u64().map(|n| n as u32))
        .collect();
    Ok(tokens)
}

/// Embeds a single short query string via `/hidden-embed`. Short timeout so
/// a cold/slow fat-station degrades this turn's candidate ranking instantly
/// rather than stalling it — callers fall back to lexical-only scoring on
/// any error.
pub(crate) async fn embed_query_via_mesh(query: &str) -> Result<Vec<f32>> {
    let base = fat_station_base();
    let client = reqwest::Client::builder()
        .timeout(Duration::from_secs(3))
        .build()?;
    let tokens = tokenize_via_mesh(&client, &base, query).await?;
    if tokens.is_empty() {
        return Err(anyhow!("query tokenized to zero tokens"));
    }
    let resp = client
        .post(format!("{}/hidden-embed", base))
        .body(tokens_to_body(&tokens))
        .send()
        .await
        .map_err(|e| anyhow!("/hidden-embed request failed: {}", e))?;
    if !resp.status().is_success() {
        let status = resp.status();
        let body = resp.text().await.unwrap_or_default();
        return Err(anyhow!("/hidden-embed returned {}: {}", status, body));
    }
    let bytes = resp
        .bytes()
        .await
        .map_err(|e| anyhow!("/hidden-embed body read failed: {}", e))?;
    Ok(body_to_f32(&bytes))
}

/// Batch-embeds every `(name, description)` text not already in the cache,
/// via one `/hidden-embed-batch` call, and persists each result. Failures
/// are logged and swallowed — the session proceeds with lexical-only
/// scoring for whatever didn't get embedded this pass; it'll retry next
/// session since a cache miss is exactly what triggers this in the first
/// place.
pub(crate) async fn ensure_tool_embeddings(catalog: &AgentToolIndex, cache: &mut ToolEmbedCache) {
    if !super::tool_embed_cache::enabled() {
        return;
    }
    let misses: Vec<&AgentIndexedTool> = catalog
        .tools
        .iter()
        .filter(|t| cache.get(content_key(&t.name, &t.description)).is_none())
        .collect();
    if misses.is_empty() {
        return;
    }

    let base = fat_station_base();
    let client = match reqwest::Client::builder()
        .timeout(Duration::from_secs(30))
        .build()
    {
        Ok(c) => c,
        Err(error) => {
            eprintln!("[semantic-tools] client build failed: {error}");
            return;
        }
    };

    let mut sequences: Vec<(u64, Vec<u32>)> = Vec::with_capacity(misses.len());
    for tool in &misses {
        let text = format!("{}: {}", tool.name, tool.description);
        match tokenize_via_mesh(&client, &base, &text).await {
            Ok(tokens) if !tokens.is_empty() => {
                sequences.push((content_key(&tool.name, &tool.description), tokens));
            }
            Ok(_) => {}
            Err(error) => {
                eprintln!("[semantic-tools] tokenize failed for {}: {error}", tool.name);
            }
        }
    }
    if sequences.is_empty() {
        return;
    }

    let mut body = Vec::new();
    body.extend_from_slice(&(sequences.len() as u32).to_le_bytes());
    for (_, tokens) in &sequences {
        body.extend_from_slice(&(tokens.len() as u32).to_le_bytes());
        for t in tokens {
            body.extend_from_slice(&t.to_le_bytes());
        }
    }

    let resp = match client
        .post(format!("{}/hidden-embed-batch", base))
        .body(body)
        .send()
        .await
    {
        Ok(r) => r,
        Err(error) => {
            eprintln!("[semantic-tools] /hidden-embed-batch request failed: {error}");
            return;
        }
    };
    if !resp.status().is_success() {
        let status = resp.status();
        let text = resp.text().await.unwrap_or_default();
        eprintln!("[semantic-tools] /hidden-embed-batch returned {status}: {text}");
        return;
    }
    let bytes = match resp.bytes().await {
        Ok(b) => b,
        Err(error) => {
            eprintln!("[semantic-tools] /hidden-embed-batch body read failed: {error}");
            return;
        }
    };
    let flat = body_to_f32(&bytes);
    if sequences.is_empty() || flat.len() % sequences.len() != 0 {
        eprintln!(
            "[semantic-tools] /hidden-embed-batch response length {} not divisible by {} sequences",
            flat.len(),
            sequences.len()
        );
        return;
    }
    let dim = flat.len() / sequences.len();
    for (i, (key, _)) in sequences.iter().enumerate() {
        let vector = flat[i * dim..(i + 1) * dim].to_vec();
        cache.insert_and_persist(*key, vector);
    }
}

pub(crate) fn cosine_similarity(a: &[f32], b: &[f32]) -> f32 {
    if a.len() != b.len() || a.is_empty() {
        return 0.0;
    }
    let mut dot = 0f32;
    let mut norm_a = 0f32;
    let mut norm_b = 0f32;
    for i in 0..a.len() {
        dot += a[i] * b[i];
        norm_a += a[i] * a[i];
        norm_b += b[i] * b[i];
    }
    if norm_a == 0.0 || norm_b == 0.0 {
        return 0.0;
    }
    dot / (norm_a.sqrt() * norm_b.sqrt())
}

/// Everything `semantic_score_indexed_tool` needs to score one turn's
/// candidates: the live query's embedding plus the persistent
/// tool-embedding cache.
pub(crate) struct SemanticContext<'a> {
    pub(crate) query_vec: &'a [f32],
    pub(crate) cache: &'a ToolEmbedCache,
}

/// Cosine similarity, rescaled to roughly the lexical scorer's magnitude —
/// `None` on a per-tool cache miss, so that one tool falls back to lexical
/// scoring instead of silently scoring 0 and vanishing from consideration.
pub(crate) fn semantic_score_indexed_tool(
    tool: &AgentIndexedTool,
    ctx: &SemanticContext<'_>,
) -> Option<f64> {
    let key = content_key(&tool.name, &tool.description);
    let tool_vec = ctx.cache.get(key)?;
    let similarity = cosine_similarity(ctx.query_vec, tool_vec) as f64;
    // Cosine is in [-1, 1]; rescale to [0, 30] so it sits in the same rough
    // magnitude as the lexical scorer's tiers (20/10/5/1 plus bonuses).
    Some(((similarity + 1.0) / 2.0) * 30.0)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn cosine_similarity_of_identical_vectors_is_one() {
        let v = vec![1.0f32, 2.0, 3.0];
        assert!((cosine_similarity(&v, &v) - 1.0).abs() < 1e-6);
    }

    #[test]
    fn cosine_similarity_of_orthogonal_vectors_is_zero() {
        let a = vec![1.0f32, 0.0];
        let b = vec![0.0f32, 1.0];
        assert!(cosine_similarity(&a, &b).abs() < 1e-6);
    }

    #[test]
    fn cosine_similarity_mismatched_length_is_zero() {
        assert_eq!(cosine_similarity(&[1.0, 2.0], &[1.0]), 0.0);
    }
}
